// Protect Route 
const express = require('express');
const authMiddleware = require('/self_learn18/express-learning/node_modules/src/middleware/authMiddleware');

const router = express.Router();
router.get("/profile", authMiddleware, (req, res) => {

        res.json({
            message: "Welcome",
            user: req.body,
        });


});

module.exports = router;
